353	/**
354	 * KRN-09 — kind of substitution applied to a curtain-wall grid cell.
355	 *
356	 * - `empty`: leave the cell open (no glass, no solid panel; mullions stay).
357	 * - `system`: render the cell as a solid panel using a registered
358	 *   `materialKey`. Falls back to glass if no `materialKey` is supplied.
359	 * - `family_instance`: instantiate a custom family at this cell. Until
360	 *   FAM-01 lands the renderer paints a placeholder panel and emits a TODO.
361	 */
362	export type CurtainPanelOverrideKind = 'empty' | 'system' | 'family_instance';
363	
364	export type CurtainPanelOverride = {
365	  kind: CurtainPanelOverrideKind;
366	  /** For `family_instance` overrides — id of the family type to instantiate. */
367	  familyTypeId?: string | null;
368	  /** For `system` overrides — `materialKey` resolved against the MAT-01 registry. */
369	  materialKey?: string | null;
370	};
