462	 *  rejected by the engine. */
463	export type CreateConstraintCmd = {
464	  type: 'createConstraint';
465	  id: string;
466	  rule: ConstraintRule;
467	  refsA: ConstraintRefRow[];
468	  refsB: ConstraintRefRow[];
