661	      ifcClassificationCode?: string | null;
662	      pinned?: boolean;
663	      /** SKB-08 phase tag — carried forward when materialised from a mass. */
664	      phaseId?: string | null;
665	      phaseCreated?: string | null;
666	      phaseDemolished?: string | null;
667	      /** KRN-V3-02: stacked wall definition. When set, components are stacked base-up. */
668	      stack?: WallStack;
669	      /** KRN-V3-07: top-vs-base XY offset for leaning walls (mm). */
670	      leanMm?: { xMm: number; yMm: number } | null;
671	      /** KRN-V3-07: top thickness / base thickness ratio; 1 = prismatic, must be in (0.1, 10). */
672	      taperRatio?: number | null;
673	      /** CMD-V3-02: provenance trace linking this element to its originating bundle. */
674	      agentTrace?: AgentTrace;
675	      /** KRN-V3-04: design option membership. */
676	      optionSetId?: string | null;
677	      optionId?: string | null;
678	      /** DSC-V3-01: discipline tag. */
679	      discipline?: DisciplineTag | null;
680	    }
